with.script:
const webhookUrl = process.env.WEBHOOK_URL;
if (!webhookUrl) {
  core.info('DISCORD_CONTRIBUTORS_WEBHOOK not set - skipping');
  return;
}

const issue = context.payload.issue;
const labels = issue.labels.map(l => l.name);
const size = labels.find(l => l.startsWith('size:')) || '';
const markers = [];
if (labels.includes('good-first-issue')) markers.push('good first issue');
if (labels.includes('help-wanted')) markers.push('help wanted');

const fields = [
  { name: 'Issue', value: `[#${issue.number} ${issue.title}](${issue.html_url})`, inline: false },
];
if (size) fields.push({ name: 'Size', value: size, inline: true });
if (markers.length) fields.push({ name: 'Tags', value: markers.join(', '), inline: true });

const body = JSON.stringify({
  embeds: [{
    title: 'New item ready for pickup',
    color: 3066993,  // green
    fields,
    footer: { text: 'Claim it by self-assigning on GitHub.' },
  }],
});

const resp = await fetch(webhookUrl, {
  method: 'POST',
  headers: { 'Content-Type': 'application/json' },
  body,
});
if (!resp.ok) {
  core.setFailed(`Discord webhook failed: ${resp.status} ${await resp.text()}`);
} else {
  core.info(`Discord response: ${resp.status}`);
}
